export function getImageAltText(lessonId: string, fallbackTitle?: string): string {
  if (illustrationAltText[lessonId]) {
    return illustrationAltText[lessonId];
  }

  for (const [key, alt] of Object.entries(systemAltText)) {
    if (lessonId.includes(key)) {
      return alt;
    }
  }

  if (fallbackTitle) {
    return `Medical illustration for ${fallbackTitle}  -  NurseNest nursing education`;
  }

  return "NurseNest hand-drawn medical illustration for nursing education";
}

